CREATE TABLE public.scores (id uuid primary key default gen_random_uuid(), name text not null, score integer not null, created_at timestamptz not null default now()); GRANT SELECT, INSERT ON public.scores TO anon, authenticated; GRANT ALL ON public.scores TO service_role; ALTER TABLE public.scores ENABLE ROW LEVEL SECURITY; CREATE POLICY "Anyone can view scores" ON public.scores FOR SELECT USING (true); CREATE POLICY "Anyone can submit scores" ON public.scores FOR INSERT WITH CHECK (char_length(name) BETWEEN 1 AND 30 AND score >= 0);